input.command:
agent-browser eval "(() => {
  const paths = Array.from(document.querySelectorAll('path.mark-line.role-mark'));
  const colors = new Set(paths.map(p => window.getComputedStyle(p).stroke));
  return {
    pathCount: paths.length,
    distinctColors: Array.from(colors),
    colorCount: colors.size
  };
})()"

agent-browser eval "(() => {
  const paths = Array.from(document.querySelectorAll('.mark-line path'));
  const colors = new Set(paths.map(p => p.getAttribute('stroke')));
  return {
    pathCount: paths.length,
    distinctColors: Array.from(colors),
    colorCount: colors.size
  };
})()"

agent-browser eval "(() => {
  const legendLabels = Array.from(document.querySelectorAll('.role-legend-label text')).map(t => t.textContent);
  return {
    legendLabels,
    hasAAPL: legendLabels.includes('AAPL'),
    hasAMZN: legendLabels.includes('AMZN'),
    hasGOOG: legendLabels.includes('GOOG')
  };
})()"
